        }
        return true;
    };

    // Try to make all numbers in nums2 even
    const canBeAllEven = () => {
        for (let i = 0; i < n; i++) {
            let possibleEven = false;

            // Option 1: nums2[i] = nums1[i]
            if (Math.abs(nums1[i]) % 2 === 0) {
                possibleEven = true;
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j], j != i
            for (let j = 0; j < n; j++) {
                if (i === j) continue;
                const diff = nums1[i] - nums1[j];
                if (Math.abs(diff) % 2 === 0) {
                    possibleEven = true;
                    break;
                }
            }

            if (!possibleEven) {
                return false;
            }
        }
        return true;
    };

