class Solution {
    /**
     * Checks if it's possible to construct nums2 such that all elements are even.
     * For each i, nums2[i] must be even, either nums1[i] or nums1[i] - nums1[j] (j!=i).
     */
    private boolean canBeAllEven(long[] nums1) {
        int n = nums1.length;
        for (int i = 0; i < n; i++) {
            boolean possibleEven = false;

            // Option 1: nums2[i] = nums1[i]
            // Since we are checking parity, the sign doesn't matter for even/odd.
            if (Math.abs(nums1[i]) % 2 == 0) {
                possibleEven = true;
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j], j != i
            for (int j = 0; j < n; j++) {
                if (i == j) continue;
                long diff = nums1[i] - nums1[j];
                if (Math.abs(diff) % 2 == 0) {
                    possibleEven = true;
                    break;
                }
            }

            if (!possibleEven) {
                return false;
            }
        }
        return true;
    }

    /**
     * Checks if it's possible to construct nums2 such that all elements are odd.
     * For each i, nums2[i] must be odd, either nums1[i] or nums1[i] - nums1[j] (j!=i).
     */
    private boolean canBeAllOdd(long[] nums1) {
        int n = nums1.length;
        for (int i = 0; i < n; i++) {
            boolean possibleOdd = false;

            // Option 1: nums2[i] = nums1[i]
